@page "/privacy"
@attribute [RenderModeAttribute()] 

@using Microsoft.AspNetCore.Http
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (_hasConsent)
{
    <div class="alert alert-success">
        ✓ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        You have not yet accepted our cookie policy.
    </div>
}

<h2>Our Policy</h2>
<p>
    This application uses cookies to ensure you get the best experience.
    We respect your privacy and are committed to protecting your personal data.
</p>

@code {
    private bool _hasConsent;

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            _hasConsent = httpContext.Request.Cookies.ContainsKey("consent");
        }
    }
}

// The Privacy page intentionally has NO interactive render mode applied.
// It uses @attribute [RenderModeAttribute()] in the .razor file which is a
// marker recognized by the custom App.razor logic below to keep the page
// in static SSR so that HttpContext is available.
//
// No code-behind is strictly needed; this file is here only for documentation.

